const Q_GEOGRAPHY_2011=[{"id": "objective>Geography>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The inhabitants of Abu are most likely to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">traders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cattle rearers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">miners</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is the presence of a scattered cultivation. The inhabitants of Abu are most likely to be farmers.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The distribution of settlements in the area is mostly influenced by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral deposits</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most of the elements are located along pass & lowlands or the feet of the hills.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The spot height on the map is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">320m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">360m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">440m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The last contour line to the spot height on the map is 350m.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area can be described as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low plain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rugged relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flood plain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plateau</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are 6 hills with different peaks with steep sides.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature shown north of Abu is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a spur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a col</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a ridge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an embankment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The apex of the 'v' shape of the higher contour points to the next lower one.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A map with a scale of 1:40,000 is reduced to one quarter of its size, what is the new scale?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:10,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:50,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:160,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:200,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a map is reduced to one quarter of its size, the scale is quadrupled. This is because the scale of a map is the ratio of a distance on the map to the corresponding distance on the ground. Therefore, if the map is reduced to one quarter of its size, the distance on the map is now one quarter of what it was, but the corresponding distance on the ground remains the same. Therefore, the new scale is 1:40,000 x 4 = 1:160,000.</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram to answer this question</em></strong>* <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If the total number of livestock is 6 million, what is the number of cattle produced?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 200 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 300 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 400 000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 500 000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Goat percentage = 4%  <br/>  Total livestock 6 million  <br/> Total number of cattle = 40/1000 x 6,000,000/1 = 4 x 600,000  <br/>  = 2,400,000.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram to answer this question</em></strong>* <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The total number of pigs, camels and donkeys is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,600,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,500,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,400,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,300,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pigs = 5%, Camel = 10%  <br/>  and donkey = 10%  <br/>  5% + 10% + 10% = 25%  <br/>  25/100 × 6,000,000  <br/> = 1,500,000</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An instrument used for setting out right angle in surveying a parcel of land is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a ranging pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an optical square</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a measuring rod</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abney level</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is used in surveying for sighting angle between two poles.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a great circle is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the equator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the earth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latitude 66<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">latitude 23<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A great circle is the largest circle that can be drawn on a sphere. It is the intersection of the sphere with a plane that passes through the center of the sphere. On the Earth, the equator is an example of a great circle. Other examples of great circles include all meridians of longitude, which intersect the North and South Poles, and the equator. Latitudes other than the equator are not great circles, they are smaller circles.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metamorphosed form of shale is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">schist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marble </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quartzite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gneiss</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Schist is a medium-grade metamorphic rock with medium to large, flat, sheet-like grains in a preferred orientation (nearby grains are roughly parallel).</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sandstone can be classified as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">argillaceous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcareous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonaceous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">arenaceous</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sandstone is a type of sedimentary rock that is primarily composed of sand-sized mineral particles or rock fragments, hence it is classified as arenaceous. The term 'arenaceous' is derived from the Latin word 'arena' which means sand.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Karst feature in its advanced stage of development is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terra rosa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sink hole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Karst valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Karst window </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Karst topography is a landscape formed from the dissolution of soluble rocks such as limestone, dolomite, and gypsum. It is characterized by underground drainage systems with sinkholes, dolines, and caves and then at advanced stages,Karst valley. </div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The common features of the middle course of a river are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">U-shaped valley and flood plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V-shaped valley and rapids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">broad interfluves and distributaries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interlocking spurs and meanders</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are major features of the middle course. The common features of the middle course of a river are interlocking spurs and meanders.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of chemical weathering is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fragmentation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exfoliation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbonation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shattering</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbonation is a form of chemical weathering. It occurs when carbon dioxide in the air or water reacts with minerals in rocks, causing them to dissolve. The other options listed, fragmentation, exfoliation, and shattering, are all forms of physical weathering, which involves the breakdown of rocks without any change in their chemical composition.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ocean currents affect the coast they wash when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevailing winds are offshore </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevailing winds are onshore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are no prevailing winds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ocean floods the shore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As they blow over the ocean, they either carry water or not depending on whether they are cold or warm current.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wind vane is used to record the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">speed of the wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">type of wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">force of the wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direction of the wind</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A weather vane, wind vane, or weathercock is an instrument for showing the direction of the wind. They are typically used as an architectural ornament to the highest point of a building.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the climate of a station with an annual rainfall of 2650mm spread fairly all year round and a mean annual temperature of 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tropical wet and dry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical monsoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical humid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean woodland</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The climate described in the question is a Tropical humid climate. This type of climate is characterized by high temperatures (mean annual temperature of 27 degrees Celsius) and high rainfall (2650mm) spread fairly all year round. Tropical wet and dry climate has a distinct dry season, which is not mentioned in the question. Tropical monsoon climate has a very heavy but short rainy season. Mediterranean woodland climate has hot, dry summers and mild, wet winters, which is not the case here.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following types of vegetation is characterized by acidic soils?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahel Savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coniferous forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperate grassland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steppe</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High solar radiation & evaporation as the soil is often exposed and this increases acidic content.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When both the macropores and the micropores are filled with water, the soil is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leached </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at field capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water logged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">erodeil</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When both the macropores and the micropores are filled with water, the soil is said to be waterlogged. Macropores and micropores are spaces in the soil. When these spaces are filled with water, it prevents air from getting to the roots of plants, causing the soil to be waterlogged.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mature soil with distinct horizons occurring in a particular climatic zone, but influenced strongly by topography is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zonal soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intrazonal soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">azonal soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alluvial soil</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intrazonal soils are mature soils with distinct horizons occurring in a particular climatic zone, but influenced strongly by topography. They are soils that have developed under conditions of a particular climate, but their formation is strongly influenced by local factors such as topography.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following resources is non-renewable?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wind energy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solar energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydro energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear energy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nuclear energy is a non-renewable resource. It is produced from uranium, a non-renewable resource that exists in limited quantities in the Earth's crust. Once these reserves are depleted, they cannot be replenished.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The introduction of materials that have negative impacts on the ecosystem is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pollution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combustion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The introduction of materials that have negative impacts on the ecosystem is known as pollution. Pollution refers to the introduction of harmful materials into the environment. These harmful materials are called pollutants. Pollutants can be natural, such as volcanic ash, or created by human activity, such as trash or runoff produced by factories. Pollutants damage the quality of air, water, and land.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a climatic hazard is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volcanic eruption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthquake </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hurricane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coastal erosion</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A climatic hazard is a type of disaster that is caused by weather or climate. This includes hurricanes, tornadoes, blizzards, and droughts. A hurricane is a type of storm that occurs in tropical or subtropical areas, typically in the summer or fall. Hurricanes are characterized by their strong, spiraling winds and heavy rainfall. They can cause significant damage to buildings and infrastructure, as well as loss of life.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following regions is high population density attributable to agricultural development?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Ruhr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nile Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Amazon Basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Midlands of England</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High population density is often attributable to agricultural development, as agriculture provides food and employment opportunities, which attract people to an area. The Nile Basin is a prime example of this. The Nile River provides a fertile valley in the middle of the desert, which has allowed for intensive agriculture for thousands of years. This has led to a high population density in the region.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements best describes the population of Southeast Asia?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High density and high growth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">High density and low growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low density and high growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low density and low growth rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Southeast Asia is known for its high population density due to the concentration of people in urban areas and fertile plains. It also has a high growth rate due to high birth rates and declining death rates. This is due to factors such as improved healthcare and living conditions.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following population characteristics is associated with developed countries?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Declining birth rate and high death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">High birth rate and declining death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High birth rate and low death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low birth rate and low death rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Developed countries are characterized by low birth rates and low death rates. This is due to factors such as better healthcare, education, and access to contraception, which lead to smaller family sizes and longer life expectancy.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Urban settlements mainly engage in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary economic activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary economic activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary economic activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quaternary economic activities</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It includes both secondary and tertiary activities.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos, Sydney, Singapore, Hong Kong and Calabar are cities which have attained considerable importance because they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are cross roads of international airlines</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have seaports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are densely populated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are administrative capitals</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos, Sydney, Singapore, Hong Kong and Calabar are cities that have attained considerable importance because they have seaports. Seaports are crucial for international trade as they facilitate the import and export of goods. This makes cities with seaports significant hubs of economic activity.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following arranges the settlement types in descending order in terms of complexity of functions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metropolis, city, town, village and hamlet</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metropolis, town, city, hamlet and village</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metropolis, city, village, hamlet and town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hamlet, village, town, city and metropolis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct arrangement of settlement types in descending order in terms of complexity of functions is Metropolis, city, town, village and hamlet. A metropolis is a large city, often the most important city in a large area or country, with many people and activities. A city is a large or important town, while a town is a built-up area with a name, defined boundaries, and local government, that is larger than a village and generally smaller than a city. A village is a group of houses and associated buildings, larger than a hamlet and usually smaller than a town, and sometimes (as in parts of the U.S.) incorporated as a municipality. Lastly, a hamlet is a small settlement, generally one smaller than a village, and strictly (in Britain) one without a church.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following economic activities are classified as primary?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Farming, transportation, fishing and manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lumbering, banking, transportation and farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fishing, lumbering, farming and mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining, trading, farming and lumbering</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Primary economic activities are those that involve the extraction of resources directly from the Earth. This includes activities such as fishing, lumbering, farming, and mining. These activities are considered primary because they involve the production of raw materials that can be transferred into a final product. Hence, the correct answer is 'Fishing, lumbering, farming and mining'.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a manufacturing enterprise produces goods which form raw materials for other enterprises, it is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">value added</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sub-contracting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forward linkage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">backward linkage</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the process of entering an agreement to perform certain work to complement the production of another company.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Most less developed nations are trade debtors because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">of their continuous link with colonial masters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the gross inbalance in international trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they import manufactured goods from industrialized nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their currencies are weak</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Their economy produces raw materials but imports most of the finished goods.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Large-scale wheat production is associated with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kano Plains and Ghezira plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghezira Plains and the Pampas of Argentina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prairies of North America and the Pampas of Argentina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ganges Plains and the Pampas of Argentina</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Large-scale wheat production is associated with the Prairies of North America and the Pampas of Argentina. These regions have the ideal climate and soil conditions for wheat cultivation, and they are known for their extensive wheat fields.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Malaysia and Indonesia are known for the production of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cocoa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coffee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tea</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Malaysia and Indonesia are known for the production of rubber. These countries have tropical climates which are suitable for the growth of rubber trees. Rubber is a major export product for these countries.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major means of transportation of goods from the Rhine Industrial region to other European cities is by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">waterways</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rail</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the major means, especially for bulky goods.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mediterranean fruits are exported mainly to Western Europe rather than Africa because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Africa produces more fruits than the Mediterranean region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Europe is closer to the Mediterranean than most parts of Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transport facilities between Africa and Western Europe are better</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is higher demand for fruits in Western Europe than in Africa</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because there are fruits in other parts of Africa and also, Africans do not value fruits as much as the Europeans.</div>", "topic": "REGIONAL GEOGRAPHY : FRUIT FARMING IN THE MEDITERRANEAN REGIONS OF AFRICA."}, {"id": "objective>Geography>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The contribution of agriculture to Nigeria's GDP has remained largely low owing to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low price of agricultural produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of access to markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its predorminantly subsistence nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate labour supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The contribution of agriculture to Nigeria's GDP has remained largely low due to its predominantly subsistence nature. Subsistence agriculture is a type of farming in which nearly all of the crops or livestock raised are used to maintain the farmer and the farmer's family, leaving little, if any, surplus for sale or trade. This means that the output is generally low and not enough to significantly contribute to the GDP.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boat building industry is least likely to be situated in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Taraba state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kogi state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kano state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kebbi state</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is no major river in Kano State. A boat building industry is least likely to be situated in Kano state </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, bays and headlands are features associated with the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Southern Coastlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Central Highland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sokoto Plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern Scarpland</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bays and Headlands are coastal landfarms which are in the South of Nigeria.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population clusters in Kano, Kaduna and Zaria cities in Northern Nigeria in the 1960's are best explained by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cultural factors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">favourable climatic conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of major cash crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the presence of industrial employment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Production of groundnut and cotton. The population clusters in Kano, Kaduna and Zaria cities in Northern Nigeria in the 1960's are best explained by the existence of major cash crops.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nguru and Kaura Namoda settlements in Northern Nigeria are most notable for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high production centres for groundnuts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">terminal points for railway transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">towns with the worst problems of water scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quarrying settlements</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nguru and Kaura Namoda settlements in Northern Nigeria are most notable for being terminal points for railway transportation. The railway system in Nigeria was a major means of transportation during the period in question, and these settlements served as terminal points, making them notable in this regard.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scattered settlement pattern of the Tiv of the Middle Belt is owing to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">security situation in the region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agricultural practices of the region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directives of its political leaders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">religious beliefs of the people</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scattered settlement pattern of the Tiv of the Middle Belt is owing to the agricultural practices of the region. The Tiv people are predominantly farmers, and their settlement pattern is influenced by their farming activities. They tend to settle in scattered communities close to their farmlands, leading to a scattered settlement pattern.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The area marked S is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Western trough</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western upland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Obudu plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oban hills</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Found in the West where Idanre and Apata hills are.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The area shaded R is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shebshi Mountains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biu Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa Plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atlantic Mountains</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">That is Adamawa State where Adamawa hill is located.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In East Africa, more variety of crops are grown than in West Africa because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different soil types</div>", "<div style=\"font-family:Cambria;font-size:17px;\">moderate rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different ranges of altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different agricultural systems</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">North of West Africa has unfriendly climate(Sahara Desert) while East Africa has favourable climate, upland.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following African countries is landlocked?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zambia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gabon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zambia is a landlocked country in Africa. A landlocked country is a country that does not have a coastline. It is surrounded by land on all sides. Gabon, Sudan, and Mozambique all have coastlines.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relief system in East Africa is characterized by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ridge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rift valleys</div>", "<div style=\"font-family:Cambria;font-size:17px;\">escarpment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relief system in East Africa is characterized by rift valleys. A rift valley is a linear shaped lowland between several highlands or mountain ranges created by the action of a geologic rift or fault. The East African Rift system is an example of where this occurs.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lake Kariba is in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tanzania </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uganda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zambia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lake Kariba is located on the border between Zambia and Zimbabwe. Therefore, the correct option is Zambia.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Improved agricultural production in Cote d'Ivoire is mainly due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">abundant and reliable rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">good and effective transportation routes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of migrant labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">good organization and effective management </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is favourable climate for agriculture. Improved agricultural production in Cote d'Ivoire is mainly due to abundant and reliable rainfall.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}];
